524→void ALFPTacticsUnit::HandleDeath()
525→{
526→    bIsDead = true;
527→
528→	// 广播死亡事件
529→    OnDeathDelegate.Broadcast();
530→
531→    // 蓝图事件
532→    OnDeath();
533→
534→    // 通知 GameMode 敌方单位被击杀（掉落追踪）
535→    if (IsEnemy())
536→    {
537→        if (ALFPTurnGameMode* GM = Cast<ALFPTurnGameMode>(GetWorld()->GetAuthGameMode()))
538→        {
539→            GM->OnEnemyUnitKilled(this);
540→        }
541→    }
542→
543→    // 从格子上移除
544→    ALFPHexTile* CurrentTile = GetCurrentTile();
545→    if (CurrentTile)
546→    {
547→        CurrentTile->SetUnitOnTile(nullptr);
548→    }
549→
550→    // 从回合系统中移除
551→    if (ALFPTurnManager* TurnManager = GetTurnManager())
552→    {
553→        TurnManager->UnregisterUnit(this);
554→    }
555→
556→    // 禁用碰撞
557→    SetActorEnableCollision(false);
558→
559→    // 延迟销毁
560→    FTimerHandle TimerHandle;
561→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, [this]()
562→        {
563→            Destroy();
564→        }, 2.0f, false);
565→}
