597→ALFPTacticsUnit* ALFPTacticsUnit::FindBestTarget()
598→{
599→    // 获取所有玩家单位
600→    TArray<AActor*> PlayerUnits;
601→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), PlayerUnits);
602→
603→    ALFPTacticsUnit* BestTarget = nullptr;
604→    float BestThreatValue = -MAX_FLT;
605→
606→    for (AActor* Actor : PlayerUnits)
607→    {
608→        ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor);
609→        if (Unit && Unit->IsAlive() && Unit->IsAlly())
610→        {
611→            float ThreatValue = CalculateThreatValue(Unit);
612→            if (ThreatValue > BestThreatValue)
613→            {
614→                BestThreatValue = ThreatValue;
615→                BestTarget = Unit;
616→            }
617→        }
618→    }
619→
620→    return BestTarget;
621→}
