296→TArray<FLFPUnitEntry> ULFPGameInstance::GetMergeablePairs() const
297→{
298→	// 统计每个 TypeID 的出现次数
299→	TMap<FName, int32> CountMap;
300→
301→	for (const FLFPUnitEntry& Unit : PartyUnits)
302→	{
303→		if (Unit.IsValid())
304→		{
305→			CountMap.FindOrAdd(Unit.TypeID, 0)++;
306→		}
307→	}
308→	for (const FLFPUnitEntry& Unit : ReserveUnits)
309→	{
310→		if (Unit.IsValid())
311→		{
312→			CountMap.FindOrAdd(Unit.TypeID, 0)++;
313→		}
314→	}
315→
316→	// 筛选出现 >= 2 次且注册表中有进化目标的 TypeID
317→	TArray<FLFPUnitEntry> Result;
318→	for (const auto& Pair : CountMap)
319→	{
320→		if (Pair.Value >= 2 && UnitRegistry && UnitRegistry->CanEvolve(Pair.Key))
321→		{
322→			FLFPUnitEntry Entry;
323→			Entry.TypeID = Pair.Key;
324→			Entry.Tier = UnitRegistry->GetUnitTier(Pair.Key);
325→			Result.Add(Entry);
326→		}
327→	}
328→
329→	return Result;
330→}
