1184→        DeploymentWidget->OnConfirmPressed.RemoveDynamic(this, &ALFPTacticsPlayerController::ConfirmDeployment);
1185→        DeploymentWidget->RemoveFromParent();
1186→    }
1187→
1188→    bIsInDeployment = false;
