 18→
 19→void ULFPHealthBarWidget::BindToUnit(ALFPTacticsUnit* Unit)
 20→{
 21→	if (!Unit || BoundUnit == Unit) return;
 22→
 23→	// 解绑旧单位
 24→	UnbindFromUnit();
 25→
 26→	// 绑定新单位
 27→	BoundUnit = Unit;
 28→
 29→	// 订阅事件
 30→	BoundUnit->OnHealthChangedDelegate.AddDynamic(this, &ULFPHealthBarWidget::OnHealthChanged);
 31→	BoundUnit->OnDeathDelegate.AddDynamic(this, &ULFPHealthBarWidget::OnUnitDeath);
 32→
 33→	// 初始化数据
 34→	UpdateHealthBar(BoundUnit->GetCurrentHealth(), BoundUnit->GetMaxHealth());
 35→
 36→	// 显示血条
 37→	SetVisibility(ESlateVisibility::Visible);
 38→
 39→	// 更新阵营颜色
 40→	if (BoundUnit)
 41→	{
 42→		UpdateAffiliationColor(BoundUnit->GetAffiliation());
 43→	}
 44→}
 45→
 46→void ULFPHealthBarWidget::UnbindFromUnit()
 47→{
 48→	if (BoundUnit)
 49→	{
 50→		// 取消订阅事件
 51→		BoundUnit->OnHealthChangedDelegate.RemoveDynamic(this, &ULFPHealthBarWidget::OnHealthChanged);
 52→		BoundUnit->OnDeathDelegate.RemoveDynamic(this, &ULFPHealthBarWidget::OnUnitDeath);
 53→		BoundUnit = nullptr;
 54→	}
 55→
 56→	// 隐藏血条
 57→	SetVisibility(ESlateVisibility::Hidden);
 58→}
 59→
 60→void ULFPHealthBarWidget::UpdateHealthBar(int32 CurrentHealth, int32 MaxHealth)
 61→{
 62→	if (!HealthProgressBar || !HealthText) return;
 63→
 64→	// 计算血量百分比
 65→	float HealthPercent = (MaxHealth > 0) ? (float)CurrentHealth / MaxHealth : 0.0f;
 66→
 67→	// 更新进度条
 68→	HealthProgressBar->SetPercent(HealthPercent);
 69→
 70→	// 更新文本
 71→	FString HealthString = FString::Printf(TEXT("%d / %d"), CurrentHealth, MaxHealth);
 72→	HealthText->SetText(FText::FromString(HealthString));
 73→}
 74→
 75→void ULFPHealthBarWidget::OnHealthChanged(int32 CurrentHealth, int32 MaxHealth)
 76→{
 77→	UpdateHealthBar(CurrentHealth, MaxHealth);
 78→}
 79→
 80→void ULFPHealthBarWidget::OnUnitDeath()
 81→{
 82→	// 单位死亡时隐藏血条
 83→	SetVisibility(ESlateVisibility::Hidden);
 84→
 85→	// 可选：显示死亡效果或文本
 86→	if (HealthText)
 87→	{
 88→		HealthText->SetText(FText::FromString(TEXT("DEAD")));
 89→	}
 90→}
