138→void ALFPTurnManager::SortUnitsBySpeed()
139→{
140→    // 按速度降序排序（速度高的先行动）
141→    // Todo: 速度相同时随机排序（玩家优先于AI）
142→    TurnOrderUnits.Sort([](const ALFPTacticsUnit& A, const ALFPTacticsUnit& B) {
143→        return A.GetSpeed() > B.GetSpeed();
144→        });
145→}
